{
  "url": "https://www.accuweather.com/es/cl/puerto-montt/821/current-weather/821",
  "extractorOptions": {
    "mode": "llm-extraction",
    "extractionSchema": {
      "type": "object",
      "properties": {
        "main": {
          "type": "object",
          "description": "Datos meteorológicos principales",
          "properties": {
            "temp": { "type": "number", "description": "Temperatura principal en °C" },
            "feels_like": { "type": "number", "description": "Sensación térmica en °C" },
            "pressure": { "type": "number", "description": "Presión en milibares (mb)" },
            "humidity": { "type": "number", "description": "Humedad en porcentaje (%)" }
          },
          "required": ["temp", "feels_like", "pressure", "humidity"]
        },
        "weather": {
          "type": "array",
          "description": "Descripción del tiempo actual",
          "items": {
            "type": "object",
            "properties": {
              "description": { "type": "string", "description": "Descripción textual del tiempo" }
            },
            "required": ["description"]
          }
        },
        "wind": {
          "type": "object",
          "description": "Información del viento",
          "properties": {
            "speed": { "type": "number", "description": "Velocidad del viento en km/h (extraído de 'Viento')" },
            "direction_text": { "type": "string", "description": "Dirección del viento como texto o letra (extraído de 'Viento')" },
            "gust": { "type": "number", "description": "Velocidad de las ráfagas de viento en km/h (extraído de 'Ráfagas', si disponible)" }
          },
          "required": ["speed", "direction_text"]
        },
        "clouds": {
          "type": "object",
          "description": "Información de nubosidad",
          "properties": {
            "all": { "type": "number", "description": "Porcentaje de nubosidad (%) (extraído de 'Nubosidad')" }
          },
          "required": ["all"]
        },
        "visibility": { "type": "number", "description": "Visibilidad en kilómetros (km) (extraído de 'Visibilidad')" },
        "sys": {
          "type": "object",
          "description": "Horas de salida y puesta del sol",
          "properties": {
            "sunrise": { "type": "string", "description": "Hora de salida del sol (texto)" },
            "sunset": { "type": "string", "description": "Hora de puesta del sol (texto)" }
          },
          "required": ["sunrise", "sunset"]
        },
        "name": { "type": "string", "description": "Nombre de la ubicación (ej. Puerto Montt)" }
      },
      "required": ["main", "weather", "wind", "clouds", "visibility", "sys", "name"]
    }
  }
}

parameters.jsCode:
// Obtener la salida del nodo anterior (HTTP Request)
// $json se refiere al primer item del array de entrada
const firecrawlOutput = $json.data; // CORREGIDO: Acceder directamente a la propiedad 'data'
const extracted = firecrawlOutput.llm_extraction;

// Crear el nuevo objeto con el formato OWM deseado
const newItem = {};

// --- Mapear Campos ---

// coord (No disponible, poner null o valores fijos si los conoces)
newItem.coord = {
  lon: null, // No extraído de Accuweather
  lat: null  // No extraído de Accuweather
};

// weather (Mapear la descripción)
newItem.weather = [];
if (extracted.weather && extracted.weather.length > 0) {
  newItem.weather.push({
    id: null, // No extraído
    main: null, // Podrías intentar mapear 'Soleado' a 'Clear', etc. si quieres
    description: extracted.weather[0].description,
    icon: null // No extraído
  });
} else {
   newItem.weather.push({ id: null, main: null, description: null, icon: null });
}


// base (Valor fijo)
newItem.base = "stations";

// main (Mapear los datos existentes)
newItem.main = {
  temp: extracted.main.temp,
  feels_like: extracted.main.feels_like,
  temp_min: extracted.main.temp, // Asumir temp_min = temp actual
  temp_max: extracted.main.temp, // Asumir temp_max = temp actual
  pressure: extracted.main.pressure,
  humidity: extracted.main.humidity,
  sea_level: extracted.main.pressure, // Asumir sea_level = pressure
  grnd_level: null // No extraído
};

// visibility (Convertir km a metros)
newItem.visibility = extracted.visibility ? extracted.visibility * 1000 : null;

// wind (Mapear velocidad, dirección texto, opcionalmente convertir unidades si OWM espera m/s)
// OWM espera speed en m/s. Firecrawl dio km/h. 1 km/h = 1/3.6 m/s
const windSpeedMs = extracted.wind.speed ? parseFloat((extracted.wind.speed / 3.6).toFixed(2)) : null;
const windGustMs = extracted.wind.gust ? parseFloat((extracted.wind.gust / 3.6).toFixed(2)) : null;

newItem.wind = {
  speed: windSpeedMs,
  deg: null, // No tenemos dirección en grados
  direction_text: extracted.wind.direction_text, // Añadido para mantener la info
  gust: windGustMs
};

// clouds (Mapear directamente)
newItem.clouds = {
  all: extracted.clouds.all
};

// dt (Timestamp de la extracción - usar el actual)
newItem.dt = Math.floor(Date.now() / 1000);

// sys (Mapear salida/puesta sol, añadir fijos)
// OWM espera timestamps UNIX. Tenemos strings "HH:MM". Convertirlos requiere la fecha.
// Por simplicidad, los dejamos como strings o null. O puedes poner el timestamp actual.
newItem.sys = {
  type: null, // No extraído
  id: null,   // No extraído
  country: "CL", // Asumir Chile
  sunrise: extracted.sys.sunrise, // Mantener como string o convertir a timestamp si sabes la fecha
  sunset: extracted.sys.sunset   // Mantener como string o convertir a timestamp si sabes la fecha
};

// timezone (No disponible)
newItem.timezone = -14400; // Valor fijo para Chile continental (GMT-4), ajustar si es necesario (GMT-3 en verano?)

// id (ID de la ciudad OWM - No disponible)
newItem.id = 3874960; // Valor fijo para Puerto Montt

// name (Mapear directamente)
newItem.name = extracted.name;

// cod (Código de estado - fijo)
newItem.cod = 200;


// Retornar el nuevo objeto formateado para que n8n lo use
// Es importante devolver un array de items, cada uno con una propiedad 'json'.
return [{ json: newItem }];
